-- ملء محتوى عنقود "النوازل المعاصرة" (nawazil-muasira) — ستة تصنيفات
-- فرعية draft بالكامل: النوازل المالية (nawazil-maliya)، النوازل
-- التقنية والذكاء الاصطناعي والخصوصية (nawazil-tiqniyya)، النوازل
-- الأسرية (nawazil-usariyya)، النوازل البيئية (nawazil-biiya)، العقود
-- الإلكترونية والعمل عن بعد (uqud-electronic)، الفضاء والعبادات
-- (fada-ibadat). كل تصنيف يحصل على درس واحد (lessons +
-- lesson_sections + lesson_citations)، بأسلوب الدفعات السابقة (body +
-- examples). المصادر المعتمدة المسمّاة صراحة لكل درس، تحقَّقت عبر
-- WebSearch/WebFetch من نصها الرسمي مباشرة قبل الصياغة (كلها فتاوى دار
-- الإفتاء المصرية):
-- 1) النوازل المالية: فتوى رقم 4205 (حكم تداول عملة البيتكوين،
--    28-12-2017م، أ.د/ شوقي إبراهيم علام).
-- 2) النوازل التقنية: فتوى رقم 8784 (حكم الاعتماد على تطبيقات الذكاء
--    الاصطناعي في الحصول على فتاوى شرعية، 22-9-2025م، أ.د/ نظير محمد
--    عياد).
-- 3) النوازل الأسرية: فتوى رقم 503 (حكم الإخصاب الصناعي وطفل الأنابيب
--    وتأجير الأرحام، 7-2-2006م، أ.د/ علي جمعة).
-- 4) النوازل البيئية: فتوى رقم 8216 (مدى حماية ورعاية البيئة في
--    الإسلام، 4-1-2024م، أ.د/ شوقي إبراهيم علام).
-- 5) العقود الإلكترونية: فتوى رقم 8152 (تكلفة إرجاع السلعة عند الشراء
--    أون لاين وجواز البيع الإلكتروني، 10-12-2023م، أ.د/ شوقي إبراهيم
--    علام).
-- 6) الفضاء والعبادات: فتوى رقم 8535 (كيفية تطهر رائد الفضاء وصلاته في
--    الفضاء الخارجي، 13-1-2025م، أ.د/ نظير محمد عياد).
-- ست آيات تحقَّقت حرفياً محليًا من artifacts/majalis/public/data/quran
-- عبر numberInSurah: النساء 29، النحل 43، الأحزاب 5، الأعراف 85،
-- المائدة 1، التغابن 16. ستة أحاديث تحقَّقت عبر WebSearch من نصها
-- وتخريجها ودرجتها بدقة: نهي النبي عن بيع الغرر (مسلم 1513، من أفراد
-- مسلم)، حديث اتخاذ الناس رءوسًا جهالًا يفتون بغير علم (متفق عليه،
-- البخاري 100 ومسلم 2673)، حديث "الولد للفراش وللعاهر الحجر" (متفق
-- عليه، البخاري 6818 ومسلم 1458)، حديث غرس الفسيلة ولو قامت الساعة
-- (رواه أحمد والبخاري في الأدب المفرد، صححه الألباني في السلسلة
-- الصحيحة)، حديث "البيعان بالخيار ما لم يتفرقا" (متفق عليه، البخاري
-- 2079 ومسلم 1532)، حديث "ما نهيتكم عنه فاجتنبوه وما أمرتكم به فأتوا
-- منه ما استطعتم" (متفق عليه، البخاري 7288). idempotent (حارس NOT
-- EXISTS بالعنوان+التصنيف) ثم status='published' للتصنيفات الستة عند
-- اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) النوازل المالية: البيتكوين
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='549c54a1-3279-43a5-b77d-6e451bc818c1' AND title='حكم تداول عملة البيتكوين والتعامل بها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حكم تداول عملة البيتكوين والتعامل بها', 'بيان حكم تداول عملة البيتكوين بيعًا وشراءً وأسباب تحريمه شرعًا كما جاء في فتوى دار الإفتاء المصرية رقم 4205', '549c54a1-3279-43a5-b77d-6e451bc818c1', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'تحريم تداول البيتكوين لآثاره الاقتصادية وما يشتمل عليه من غرر وجهالة', 'بيّنت الفتوى، بعد بحث مستفيض ورجوع لخبراء الاقتصاد والجهات ذات الصلة، أن تداول عملة البيتكوين والتعامل بها بيعًا وشراءً وإجارة وغيرها محرّم شرعًا. وعلّلت ذلك بجملة من الأسباب: أثرها السلبي على الاقتصاد وإخلالها باتزان السوق ومفهوم العمل المنتج، وفقدان المتعامل بها للحماية القانونية والرقابة المالية المطلوبة، وما تشتمل عليه من الافتيات على ولاة الأمور وسلب بعض اختصاصاتهم في ضبط النقد والتعامل المالي، إضافة إلى الضرر الناشئ عن الغرر والجهالة والغش في مصرفها ومعيارها وقيمتها، وما يترتب عليها من مخاطر عالية على الأفراد والدول لعدم توافر الصفات المطلوبة في العملات المعتمدة. وطبّقت الفتوى القاعدة الفقهية العامة "لا ضرر ولا ضرار" لتأصيل هذا الحكم.', 1),
    (v_lesson, 'examples', 'آية أكل الأموال بالباطل وحديث النهي عن بيع الغرر', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَأْكُلُوا أَمْوَالَكُم بَيْنَكُم بِالْبَاطِلِ إِلَّا أَن تَكُونَ تِجَارَةً عَن تَرَاضٍ مِّنكُمْ﴾ (النساء: 29)، وهي الأصل القرآني في حصر أكل المال المشروع في التجارة الصادرة عن رضا حقيقي بعيدًا عن الغرر والجهالة، وهو ما استندت إليه الفتوى في وصف التعامل بالبيتكوين بأنه اشتمل على أكل للمال بالباطل. وفي بيان الأصل الفقهي في منع المعاملات المجهولة العاقبة، عن أبي هريرة رضي الله عنه أن النبي صلى الله عليه وسلم نهى عن بيع الحصاة وعن بيع الغرر (رواه مسلم 1513، وهو من أفراد مسلم على البخاري). فهذا الحديث هو الأصل الذي بنت عليه الفتوى وصفها للتعامل بالبيتكوين بالغرر والجهالة في مصرفه ومعياره وقيمته.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'دار الإفتاء المصرية، فتوى رقم 4205: حكم تداول عملة البيتكوين والتعامل بها (28 ديسمبر 2017م، أ.د/ شوقي إبراهيم علام)', 1);
  END IF;

  -- 2) النوازل التقنية والذكاء الاصطناعي والخصوصية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='d5c4faf4-0db2-4a13-89a9-050f3c2eb317' AND title='حكم الاعتماد على تطبيقات الذكاء الاصطناعي في الفتوى الشرعية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حكم الاعتماد على تطبيقات الذكاء الاصطناعي في الفتوى الشرعية', 'بيان عدم جواز الاعتماد على برامج الذكاء الاصطناعي وحدها في الحصول على فتاوى شرعية كما جاء في فتوى دار الإفتاء المصرية رقم 8784', 'd5c4faf4-0db2-4a13-89a9-050f3c2eb317', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'عدم جواز الاعتماد على الذكاء الاصطناعي وحده في استخراج الأحكام الشرعية', 'ذهبت الفتوى، ردًا على سائل يلجأ بشكل متكرر لتطبيقات الذكاء الاصطناعي للسؤال عن الأحكام الشرعية، إلى عدم جواز الاعتماد على هذه البرامج في الحصول على فتاوى شرعية معتمدة. وعلّلت ذلك بأن هذه التطبيقات تفتقر إلى المرونة البشرية والقدرة على استيعاب كامل أدوات الإفتاء من علوم ومعارف تراكمية، وأنها عاجزة عن مراعاة اختلاف الفتوى بتغير الزمان والمكان والظروف الخاصة بكل سائل، وهو ما يُعرف في أصول الفقه بفقه المآلات والنظر في الواقع. وأكدت الفتوى أن نتائج هذه البرامج قد تحتمل الخطأ دون استنادها إلى منهج علمي رصين أو معايير شرعية دقيقة، فيبقى الرجوع في الفتوى إلى أهل العلم المؤهلين هو الأصل، ويمكن الاستعانة بهذه التطبيقات كأداة مساعدة لعرض فتاوى العلماء المعتمدة لا كمصدر مستقل للفتوى.', 1),
    (v_lesson, 'examples', 'آية سؤال أهل الذكر وحديث خطر الإفتاء بغير علم', 'قال تعالى: ﴿وَمَا أَرْسَلْنَا مِن قَبْلِكَ إِلَّا رِجَالًا نُّوحِي إِلَيْهِمْ ۚ فَاسْأَلُوا أَهْلَ الذِّكْرِ إِن كُنتُمْ لَا تَعْلَمُونَ﴾ (النحل: 43)، وهي الأصل القرآني في وجوب الرجوع في مسائل الدين إلى أهل العلم المتخصصين دون سواهم، وهو ما استندت إليه الفتوى في تقرير أن أهلية الإفتاء لا تقوم بها الآلة. وفي بيان خطورة تصدر غير المؤهل للفتوى، عن عبد الله بن عمرو بن العاص رضي الله عنهما أن النبي صلى الله عليه وسلم قال: "إن الله لا يقبض العلم انتزاعًا ينتزعه من العباد، ولكن يقبض العلم بقبض العلماء، حتى إذا لم يبق عالمًا اتخذ الناس رءوسًا جهالًا، فسُئلوا فأفتوا بغير علم، فضلّوا وأضلّوا" (متفق عليه، رواه البخاري 100 ومسلم 2673). فهذا الحديث يبيّن أن الفتوى الصادرة بغير علم راسخ، سواء عن جاهل بشري أو أداة آلية لا تملك أدوات الاجتهاد، مآلها الإضلال لا الهداية.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'دار الإفتاء المصرية، فتوى رقم 8784: حكم الاعتماد على تطبيقات الذكاء الاصطناعي في الحصول على فتاوى شرعية (22 سبتمبر 2025م، أ.د/ نظير محمد عياد)', 1);
  END IF;

  -- 3) النوازل الأسرية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='cb215e59-f1b8-4537-8fa1-c17914f48f7c' AND title='حكم الإخصاب الصناعي وأطفال الأنابيب وتحريم تأجير الأرحام') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حكم الإخصاب الصناعي وأطفال الأنابيب وتحريم تأجير الأرحام', 'بيان ضوابط جواز الإخصاب الصناعي وطفل الأنابيب وتحريم تأجير الأرحام كما جاء في فتوى دار الإفتاء المصرية رقم 503', 'cb215e59-f1b8-4537-8fa1-c17914f48f7c', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'جواز طفل الأنابيب بضوابط دقيقة وتحريم تأجير الأرحام لاختلاط الأنساب', 'بيّنت الفتوى أنه يجوز شرعًا اللجوء لعملية الإخصاب الصناعي المعروفة بـ"طفل الأنابيب" بشروط محددة: توافر ضرورة طبية داعية لهذا الإجراء، وأن تكون البويضة الملقحة من الزوجة والحيوان المنوي من زوجها فقط دون خلط أو استبدال بمني إنسان آخر، وأن تُجرى العملية على يد طبيب حاذق مؤتمن، مع رد البويضة الملقحة إلى رحم الزوجة نفسها. أما تأجير الأرحام، وهو استخدام رحم امرأة أخرى (الأم البديلة) لحمل الجنين، فبيّنت الفتوى تحريمه شرعًا، لأنه لا يمكن مع وجود هذا الطرف الثالث الجزم بتحديد الأم الحقيقية للجنين، مما يترتب عليه اختلاط الأنساب والتنازع على نسبة الولد، وهذا يخالف مقصد الشارع في استقرار الأحوال الأسرية وحفظ الأنساب. وأشارت الفتوى إلى صدور قرار مجمع البحوث الإسلامية رقم 1 بتاريخ 29 مارس 2001م بتحريم تأجير الأرحام.', 1),
    (v_lesson, 'examples', 'آية نسبة الأبناء إلى آبائهم الحقيقيين وحديث الولد للفراش', 'قال تعالى: ﴿ادْعُوهُمْ لِآبَائِهِمْ هُوَ أَقْسَطُ عِندَ اللَّهِ﴾ (الأحزاب: 5)، وهي الأصل القرآني في وجوب نسبة الولد إلى أبيه الحقيقي وعدم جواز الخلط في النسب، وهو المعنى الذي بُنيت عليه ضوابط الفتوى في اشتراط أن تكون البويضة والحيوان المنوي من الزوجين فقط دون طرف ثالث. وفي بيان القاعدة الفقهية العامة في إثبات النسب، عن أبي هريرة رضي الله عنه أن النبي صلى الله عليه وسلم قال: "الولد للفراش وللعاهر الحجر" (متفق عليه، رواه البخاري 6818 ومسلم 1458). فهذا الحديث هو الأصل الذي استندت إليه الفتوى في تحريم تأجير الأرحام، إذ إن دخول رحم امرأة أجنبية عن فراش الزوجية يُدخل الشك والاختلاط فيما جعله الشرع أصلًا قاطعًا لثبوت النسب.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'دار الإفتاء المصرية، فتوى رقم 503: حكم الإخصاب الصناعي وطفل الأنابيب وتأجير الأرحام (7 فبراير 2006م، أ.د/ علي جمعة محمد)', 1);
  END IF;

  -- 4) النوازل البيئية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='e9d9c971-c086-4239-86ee-75ec81336837' AND title='عناية الإسلام بحماية البيئة ومظاهرها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('عناية الإسلام بحماية البيئة ومظاهرها', 'بيان مظاهر عناية الإسلام بحماية البيئة في الماء والهواء والأرض والحيوان كما جاء في فتوى دار الإفتاء المصرية رقم 8216', 'e9d9c971-c086-4239-86ee-75ec81336837', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'أربعة مجالات لحماية البيئة رسمها الإسلام لضمان توازنها واستقرارها', 'بيّنت الفتوى أن الإسلام أولى البيئة عناية بالغة، وأرسى منظومة متكاملة من التشريعات تكفل سلامتها وتوازنها، وتتجلى هذه العناية في أربعة مجالات رئيسية: حماية الماء، باعتباره قوام الحياة وأصل كل كائن حي، فنهى الإسلام عن الإسراف فيه حتى في العبادة، وحذّر من تلويثه بجميع أشكاله؛ وحماية الهواء، باعتباره جزءًا لا يتجزأ من المحافظة على الحياة، فحثّ على تشجير الأرض وزراعتها ونهى عن تقطيع الأشجار لغير ضرورة؛ وحماية الأرض، بالدعوة إلى استصلاحها وإحياء أراضيها الموات، والنهي عن التخلي في الطرقات وإلقاء النفايات في أماكن جلوس الناس؛ وحماية الحيوان، بالوصية بالرفق به وعدم التمثيل به والحرص على عدم إفناء سلالاته. وخلصت الفتوى إلى أن الحفاظ على مكونات البيئة مطلب شرعي يضمن سلامتها وتوازنها واستقرارها لهذا الجيل والأجيال القادمة.', 1),
    (v_lesson, 'examples', 'آية النهي عن الإفساد في الأرض وحديث غرس الفسيلة ولو قامت الساعة', 'قال تعالى على لسان شعيب عليه السلام لقومه: ﴿وَلَا تُفْسِدُوا فِي الْأَرْضِ بَعْدَ إِصْلَاحِهَا ذَٰلِكُمْ خَيْرٌ لَّكُمْ إِن كُنتُم مُّؤْمِنِينَ﴾ (الأعراف: 85)، وهي الآية التي استندت إليها الفتوى نصًّا في تأصيل مبدأ حماية البيئة وعدم الإفساد في عناصرها بعد صلاحها. وفي بيان مدى الحرص المطلوب على الإعمار والزراعة حتى في أحرج الأوقات، عن أنس بن مالك رضي الله عنه أن النبي صلى الله عليه وسلم قال: "إن قامت الساعة وفي يد أحدكم فسيلة، فإن استطاع أن لا تقوم حتى يغرسها فليغرسها" (رواه أحمد والبخاري في الأدب المفرد، وصححه الألباني في السلسلة الصحيحة). فهذا الحديث يبيّن أن العناية بالزرع والإعمار مطلوبة شرعًا حتى لو لم يُرْجَ نفعها العاجل، وهو ما يؤكد مكانة حماية البيئة في مقاصد الشريعة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'دار الإفتاء المصرية، فتوى رقم 8216: مدى حماية ورعاية البيئة في الإسلام (4 يناير 2024م، أ.د/ شوقي إبراهيم علام)', 1);
  END IF;

  -- 5) العقود الإلكترونية والعمل عن بعد
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='626a427d-0d97-4913-b2bb-35f8b12e6ab9' AND title='حكم البيع الإلكتروني (أون لاين) ومسؤولية تكلفة الإرجاع') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حكم البيع الإلكتروني (أون لاين) ومسؤولية تكلفة الإرجاع', 'بيان جواز البيع الإلكتروني وضوابطه وتحديد مسؤولية تكلفة إرجاع السلعة كما جاء في فتوى دار الإفتاء المصرية رقم 8152', '626a427d-0d97-4913-b2bb-35f8b12e6ab9', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'البيع الإلكتروني بيع غائب موصوف جائز شرعًا وتكلفة الإرجاع على المشتري ما لم يُتفق على خلافه', 'ردًّا على سؤال عن بيع كتب عبر الإنترنت مع اتفاق على حق المشتري في الإرجاع خلال أسبوعين، بيّنت الفتوى أن البيع الإلكتروني (أون لاين) يعتبر من قبيل "بيع الغائب الموصوف"، وهو جائز شرعًا عند جمهور الفقهاء متى انضبط بوصف دقيق للمبيع يرفع الجهالة عنه. وللمشتري في هذا النوع من البيع "خيار الرؤية" عند استلام السلعة إن جاءت مخالفة للوصف المتفق عليه. أما عن مسؤولية تكلفة إرجاع السلعة عند رغبة المشتري في ردها دون عيب فيها، فبيّنت الفتوى أن هذه التكلفة تقع على المشتري نفسه، استنادًا إلى نصوص فقهاء الحنفية والشافعية والحنابلة في أن "مؤنة رد المبيع" تلزم الراد، ما لم يتفق الطرفان ويتراضيا على خلاف ذلك. وأشارت الفتوى إلى أن القانون المصري رقم 181 لسنة 2018 يُلزم المورد برد المبلغ المدفوع خلال سبعة أيام، غير أن تبعة تكلفة الإرجاع تبقى على المستهلك (المشتري) ما لم يُنص على غيره في شروط التعاقد.', 1),
    (v_lesson, 'examples', 'آية الوفاء بالعقود وحديث خيار المتبايعين', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا أَوْفُوا بِالْعُقُودِ﴾ (المائدة: 1)، وهي الأصل القرآني العام الذي تُبنى عليه صحة أي عقد جديد لم يكن معروفًا زمن التنزيل، ومنه العقود الإلكترونية، ما دام قد استوفى شروط انعقاده الشرعية من رضا ووصف دقيق وخلو من الغرر المفسد. وفي بيان الأصل الفقهي في خيار المتعاقدين قبل لزوم البيع، عن حكيم بن حزام رضي الله عنه أن النبي صلى الله عليه وسلم قال: "البيّعان بالخيار ما لم يتفرَّقا، فإن صدَقا وبيَّنا بُورك لهما في بيعهما، وإن كتما وكذَبا مُحقت بركة بيعهما" (متفق عليه، رواه البخاري 2079 ومسلم 1532). فهذا الحديث أصل في مشروعية الخيار في البيوع، وهو المعنى الذي امتد في البيع الإلكتروني إلى خيار الرؤية عند استلام المبيع الغائب، حفظًا لحق المشتري من الغبن.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'دار الإفتاء المصرية، فتوى رقم 8152: تكلفة إرجاع السلعة في حالة الشراء عن طريق الإنترنت (أون لاين) (10 ديسمبر 2023م، أ.د/ شوقي إبراهيم علام)', 1);
  END IF;

  -- 6) الفضاء والعبادات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='9da42899-0955-4c28-a78f-060027878f54' AND title='كيفية طهارة رائد الفضاء وصلاته في الفضاء الخارجي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('كيفية طهارة رائد الفضاء وصلاته في الفضاء الخارجي', 'بيان مراتب طهارة رائد الفضاء المسلم وأداء صلاته حسب استطاعته كما جاء في فتوى دار الإفتاء المصرية رقم 8535', '9da42899-0955-4c28-a78f-060027878f54', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'ثلاث مراتب لطهارة رائد الفضاء تنزّلًا مع الاستطاعة الفعلية', 'بيّنت الفتوى أن طهارة رائد الفضاء المسلم استعدادًا للصلاة تتحدد وفق ثلاث حالات متدرجة بحسب استطاعته الفعلية داخل المركبة الفضائية: الحالة الأولى، إذا توفر الماء وكان فائضًا عن حاجته وقادرًا على إيصاله إلى أعضاء الوضوء رغم انعدام الجاذبية، لزمه التطهر به كسائر المسلمين. الحالة الثانية، إذا عجز عن استعمال الماء أو لم يكن فائضًا عن حاجته، لزمه التيمم بضربتين على شيء من جنس الأرض كتراب أو حجر يحمله معه، يمسح بالأولى وجهه وبالثانية يديه إلى المرفقين. الحالة الثالثة، إن عجز عن الماء والتيمم معًا لظرف المهمة الفضائية، صلّى على حسب حاله دون تطهر، وصلاته صحيحة مجزئة لا تلزمه إعادتها بعد ذلك. كما أشارت فتاوى أخرى لدار الإفتاء إلى أن رائد الفضاء الخارج عن الغلاف الجوي للأرض يفقد إمكان تحديد جهة القبلة على وجه اليقين، فيتوجه في صلاته حيث أمكنه الاجتهاد في تحديد الجهة.', 1),
    (v_lesson, 'examples', 'آية التقوى بحسب الاستطاعة وحديث الإتيان بالمأمور على قدر الطاقة', 'قال تعالى: ﴿فَاتَّقُوا اللَّهَ مَا اسْتَطَعْتُمْ وَاسْمَعُوا وَأَطِيعُوا وَأَنفِقُوا خَيْرًا لِّأَنفُسِكُمْ﴾ (التغابن: 16)، وهي الأصل القرآني العام في تعليق التكليف بقدر الاستطاعة الفعلية، وهو ما بُنيت عليه مراتب طهارة رائد الفضاء الثلاث تنزّلًا من الأكمل إلى ما دونه بحسب عجزه. وفي بيان القاعدة النبوية الجامعة لهذا المعنى، عن أبي هريرة رضي الله عنه قال: سمعت رسول الله صلى الله عليه وسلم يقول: "ما نهيتكم عنه فاجتنبوه، وما أمرتكم به فأتوا منه ما استطعتم" (متفق عليه، رواه البخاري 7288). فهذا الحديث هو الأصل الفقهي الذي استندت إليه الفتوى في تدرّج أحكام الطهارة والصلاة لرائد الفضاء بحسب ما تسمح به ظروفه الفعلية دون تكليفه بما لا يطيق.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'دار الإفتاء المصرية، فتوى رقم 8535: كيفية طهارة رائد الفضاء وصلاته (13 يناير 2025م، أ.د/ نظير محمد عياد)', 1);
  END IF;

